from flask import Flask, request, redirect

app = Flask(__name__)


@app.route('/')
def redirect():
    '''
    Redirect the user to the next_url  specified on the GET request.
    '''
    next_url = request.args.get('next_url', '')
    # Prevent open redirects by ensuring the URL is a relative path
    if next_url.startswith('/') and not next_url.startswith('//') and not next_url.startswith('http://') and not next_url.startswith('https://'):
        return redirect(next_url)
    else:
        return redirect('/')

